<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Maze Game with 24 Bots</title>
    <style>
        body {
            margin: 0;
            padding: 20px;
            background-color: #1a1a2e;
            color: #fff;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
        }

        h1 {
            margin-bottom: 10px;
            text-align: center;
            color: #e94560;
        }

        .hud {
            display: flex;
            gap: 20px;
            margin-bottom: 15px;
            background-color: rgba(255, 255, 255, 0.1);
            padding: 10px 20px;
            border-radius: 8px;
        }

        .hud-item {
            display: flex;
            flex-direction: column;
            align-items: center;
        }

        .hud-label {
            font-size: 0.9rem;
            color: #aaa;
        }

        .hud-value {
            font-size: 1.5rem;
            font-weight: bold;
            color: #e94560;
        }

        button#reset {
            background-color: #e94560;
            color: white;
            border: none;
            padding: 8px 20px;
            border-radius: 5px;
            cursor: pointer;
            font-size: 1rem;
            transition: background-color 0.3s, transform 0.1s;
        }

        button#reset:hover {
            background-color: #d6344a;
        }

        button#reset:active {
            transform: scale(0.95);
        }

        .maze-container {
            position: relative;
            border-radius: 8px;
            overflow: hidden;
            box-shadow: 0 10px 20px rgba(0, 0, 0, 0.3);
        }

        canvas#maze {
            display: block;
            background-color: #16213e;
        }

        .controls {
            margin-top: 15px;
        }
    </style>
</head>
<body>
    <h1>Maze Game with 24 Bots</h1>

    <div class="hud">
        <div class="hud-item">
            <span class="hud-label">Completed</span>
            <span id="completed" class="hud-value">0</span>
        </div>
        <div class="hud-item">
            <span class="hud-label">Time</span>
            <span id="timer" class="hud-value">0.0s</span>
        </div>
    </div>

    <div class="maze-container">
        <canvas id="maze" width="600" height="600"></canvas>
    </div>

    <div class="controls">
        <button id="reset">Reset Game</button>
    </div>

    <script>
        // Maze generation and game logic
        const CELL_SIZE = 30;
        const MAZE_ROWS = 15;
        const MAZE_COLS = 20; // Slightly wider than tall for better visual

        class Maze {
            constructor(rows, cols) {
                this.rows = rows;
                this.cols = cols;
                this.grid = [];
                this.spawn = { x: 1, y: 1 };
                this.exit = { x: cols - 2, y: rows - 2 };

                // Initialize grid with all walls
                for (let r = 0; r < rows; r++) {
                    const row = [];
                    for (let c = 0; c < cols; c++) {
                        row.push({
                            x: c,
                            y: r,
                            top: true, right: true, bottom: true, left: true
                        });
                    }
                    this.grid.push(row);
                }

                // Generate maze using recursive backtracking
                this.generateMaze();
            }

            generateMaze() {
                const stack = [];
                const visited = new Set();

                // Start from a random cell (we'll use top-left for consistency)
                let current = { x: 1, y: 1 };
                visited.add(`${current.x},${current.y}`);
                stack.push(current);

                while (stack.length > 0) {
                    current = stack[stack.length - 1];
                    const neighbors = this.getUnvisitedNeighbors(current, visited);

                    if (neighbors.length > 0) {
                        // Choose a random neighbor
                        const next = neighbors[Math.floor(Math.random() * neighbors.length)];

                        // Remove walls between current and next
                        this.removeWalls(current, next);

                        visited.add(`${next.x},${next.y}`);
                        stack.push(next);
                    } else {
                        stack.pop();
                    }
                }

                // Set spawn and exit positions (ensure they're valid)
                this.spawn = { x: 1, y: 1 };
                this.exit = { x: this.cols - 2, y: this.rows - 2 };
            }

            getUnvisitedNeighbors(cell, visited) {
                const neighbors = [];
                const directions = [
                    { dx: 0, dy: -1, dir: 'top' },    // up
                    { dx: 1, dy: 0, dir: 'right' },   // right
                    { dx: 0, dy: 1, dir: 'bottom' },  // down
                    { dx: -1, dy: 0, dir: 'left' }    // left
                ];

                for (const d of directions) {
                    const nx = cell.x + d.dx;
                    const ny = cell.y + d.dy;

                    if (nx >= 1 && nx < this.cols - 1 && 
                        ny >= 1 && ny < this.rows - 1 &&
                        !visited.has(`${nx},${ny}`)) {
                        neighbors.push({ x: nx, y: ny });
                    }
                }

                return neighbors;
            }

            removeWalls(cell1, cell2) {
                const dx = cell2.x - cell1.x;
                const dy = cell2.y - cell1.y;

                if (dx === 0 && dy === -1) { // cell2 is above cell1
                    this.grid[cell1.y][cell1.x].top = false;
                    this.grid[cell2.y][cell2.x].bottom = false;
                } else if (dx === 1 && dy === 0) { // cell2 is right of cell1
                    this.grid[cell1.y][cell1.x].right = false;
                    this.grid[cell2.y][cell2.x].left = false;
                } else if (dx === 0 && dy === 1) { // cell2 is below cell1
                    this.grid[cell1.y][cell1.x].bottom = false;
                    this.grid[cell2.y][cell2.x].top = false;
                } else if (dx === -1 && dy === 0) { // cell2 is left of cell1
                    this.grid[cell1.y][cell1.x].left = false;
                    this.grid[cell2.y][cell2.x].right = false;
                }
            }

            canMove(x, y, direction) {
                if (x < 0 || x >= this.cols || y < 0 || y >= this.rows) return false;

                const cell = this.grid[y][x];
                switch (direction) {
                    case 'up': return !cell.top;
                    case 'right': return !cell.right;
                    case 'down': return !cell.bottom;
                    case 'left': return !cell.left;
                    default: return false;
                }
            }

            getNeighbors(x, y) {
                const neighbors = [];
                if (this.canMove(x, y, 'up')) neighbors.push({ x: x, y: y - 1 });
                if (this.canMove(x, y, 'right')) neighbors.push({ x: x + 1, y: y });
                if (this.canMove(x, y, 'down')) neighbors.push({ x: x, y: y + 1 });
                if (this.canMove(x, y, 'left')) neighbors.push({ x: x - 1, y: y });

                return neighbors;
            }

            // BFS to find shortest path
            findPath(startX, startY) {
                const queue = [{ x: startX, y: startY }];
                const visited = new Set();
                visited.add(`${startX},${startY}`);
                const parentMap = new Map();

                while (queue.length > 0) {
                    const current = queue.shift();

                    if (current.x === this.exit.x && current.y === this.exit.y) {
                        // Reconstruct path
                        const path = [];
                        let curr = current;
                        while (curr.x !== startX || curr.y !== startY) {
                            path.unshift(curr);
                            const key = `${curr.x},${curr.y}`;
                            curr = parentMap.get(key);
                        }
                        return path;
                    }

                    const neighbors = this.getNeighbors(current.x, current.y);
                    for (const neighbor of neighbors) {
                        if (!visited.has(`${neighbor.x},${neighbor.y}`)) {
                            visited.add(`${neighbor.x},${neighbor.y}`);
                            parentMap.set(`${neighbor.x},${neighbor.y}`, current);
                            queue.push(neighbor);
                        }
                    }
                }

                return []; // No path found
            }

            draw(ctx) {
                ctx.fillStyle = '#16213e';
                ctx.fillRect(0, 0, this.cols * CELL_SIZE, this.rows * CELL_SIZE);

                // Draw exit
                ctx.fillStyle = '#4caf50'; // Green for exit
                const exitX = this.exit.x * CELL_SIZE + 2;
                const exitY = this.exit.y * CELL_SIZE + 2;
                const exitSize = CELL_SIZE - 4;
                ctx.fillRect(exitX, exitY, exitSize, exitSize);

                // Draw spawn
                ctx.fillStyle = '#f44336'; // Red for spawn
                const spawnX = this.spawn.x * CELL_SIZE + 5;
                const spawnY = this.spawn.y * CELL_SIZE + 5;
                ctx.fillRect(spawnX, spawnY, CELL_SIZE - 10, CELL_SIZE - 10);

                // Draw walls
                ctx.strokeStyle = '#e94560'; // Reddish for walls
                ctx.lineWidth = 2;
                ctx.beginPath();

                for (let r = 0; r < this.rows; r++) {
                    for (let c = 0; c < this.cols; c++) {
                        const cell = this.grid[r][c];

                        if (cell.top) {
                            ctx.moveTo(c * CELL_SIZE, r * CELL_SIZE);
                            ctx.lineTo((c + 1) * CELL_SIZE, r * CELL_SIZE);
                        }
                        if (cell.right) {
                            ctx.moveTo((c + 1) * CELL_SIZE, r * CELL_SIZE);
                            ctx.lineTo((c + 1) * CELL_SIZE, (r + 1) * CELL_SIZE);
                        }
                        if (cell.bottom) {
                            ctx.moveTo(c * CELL_SIZE, (r + 1) * CELL_SIZE);
                            ctx.lineTo((c + 1) * CELL_SIZE, (r + 1) * CELL_SIZE);
                        }
                        if (cell.left) {
                            ctx.moveTo(c * CELL_SIZE, r * CELL_SIZE);
                            ctx.lineTo(c * CELL_SIZE, (r + 1) * CELL_SIZE);
                        }
                    }
                }

                ctx.stroke();
            }
        }

        class Bot {
            constructor(id, startX, startY, path) {
                this.id = id;
                this.startX = startX;
                this.startY = startY;
                this.x = startX;
                this.y = startY;
                this.path = path;
                this.pathIndex = 0;
                this.completed = false;

                // Animation properties
                this.animX = startX;
                this.animY = startY;
                this.animProgress = 0;
                this.moveSpeed = 0.15; // Movement speed per frame

                // Stagger start time (random delay)
                this.startDelay = Math.random() * 20; // frames
                this.active = false;
            }

            update() {
                if (this.completed) return;

                // Apply start delay
                if (!this.active && this.startDelay > 0) {
                    this.startDelay--;
                    return;
                }

                this.active = true;

                // If we have a path and haven't completed it yet
                if (this.pathIndex < this.path.length) {
                    const target = this.path[this.pathIndex];

                    // Move toward target cell
                    const dx = target.x - this.animX;
                    const dy = target.y - this.animY;

                    // Simple interpolation for smooth movement
                    if (Math.abs(dx) > 0.1 || Math.abs(dy) > 0.1) {
                        this.animX += dx * this.moveSpeed;
                        this.animY += dy * this.moveSpeed;
                    } else {
                        // Snap to target and advance path index
                        this.x = target.x;
                        this.y = target.y;
                        this.animX = target.x;
                        this.animY = target.y;
                        this.pathIndex++;

                        // Check if we reached the exit
                        if (this.x === game.maze.exit.x && this.y === game.maze.exit.y) {
                            this.completed = true;
                        }
                    }
                } else if (!this.completed) {
                    // Should not happen, but just in case
                    this.completed = true;
                }
            }

            draw(ctx) {
                const centerX = this.animX * CELL_SIZE + CELL_SIZE / 2;
                const centerY = this.animY * CELL_SIZE + CELL_SIZE / 2;

                ctx.fillStyle = `hsl(${this.id * 15}, 70%, 60%)`;
                ctx.beginPath();
                ctx.arc(centerX, centerY, CELL_SIZE / 4, 0, Math.PI * 2);
                ctx.fill();

                // Add a glow effect
                ctx.shadowColor = ctx.fillStyle;
                ctx.shadowBlur = 10;
                ctx.stroke();
                ctx.shadowBlur = 0;
            }
        }

        class Game {
            constructor() {
                this.maze = new Maze(MAZE_ROWS, MAZE_COLS);
                this.bots = [];
                this.completedCount = 0;
                this.startTime = Date.now();
                this.isRunning = true;

                // Initialize bots
                this.initBots();

                // Setup canvas
                this.canvas = document.getElementById('maze');
                this.ctx = this.canvas.getContext('2d');

                // Update dimensions based on maze size
                this.canvas.width = MAZE_COLS * CELL_SIZE;
                this.canvas.height = MAZE_ROWS * CELL_SIZE;

                // Bind reset button
                document.getElementById('reset').addEventListener('click', () => {
                    this.reset();
                });

                // Start animation loop
                this.animate();
            }

            initBots() {
                this.bots = [];
                this.completedCount = 0;

                // Generate paths for all bots (they should all have the same optimal path)
                const path = this.maze.findPath(this.maze.spawn.x, this.maze.spawn.y);

                // Create 24 bots
                for (let i = 0; i < 24; i++) {
                    this.bots.push(new Bot(i, this.maze.spawn.x, this.maze.spawn.y, path));
                }
            }

            reset() {
                this.startTime = Date.now();
                this.isRunning = true;
                this.initBots();
            }

            tick(n) {
                // Synchronous simulation: advance n steps
                for (let step = 0; step < n; step++) {
                    let activeCount = 0;

                    for (const bot of this.bots) {
                        if (!bot.completed) {
                            bot.update();
                            activeCount++;
                        }
                    }

                    // Update completion count
                    this.completedCount = this.bots.filter(bot => bot.completed).length;

                    // If all bots completed, we can stop early
                    if (this.completedCount === 24 && step > 0) break;
                }

                // Force animation positions to match simulation positions
                for (const bot of this.bots) {
                    bot.animX = bot.x;
                    bot.animY = bot.y;
                }
            }

            animate() {
                if (!this.isRunning) return;

                // Clear canvas
                this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);

                // Draw maze
                this.maze.draw(this.ctx);

                // Update and draw bots
                for (const bot of this.bots) {
                    if (!bot.completed) {
                        bot.update();
                    }
                    bot.draw(this.ctx);
                }

                // Update HUD
                const elapsedMs = Date.now() - this.startTime;
                document.getElementById('completed').textContent = 
                    this.bots.filter(bot => bot.completed).length;
                document.getElementById('timer').textContent = 
                    (elapsedMs / 1000).toFixed(1) + 's';

                // Continue animation
                requestAnimationFrame(() => this.animate());
            }
        }

        // Initialize game and expose API
        const game = new Game();

        // Expose the required API on window
        Object.defineProperty(window, 'game', {
            value: {
                get bots() {
                    return game.bots;
                },
                get completed() {
                    return game.bots.filter(bot => bot.completed).length;
                },
                get elapsedMs() {
                    return Date.now() - game.startTime;
                },
                tick(n) {
                    // Synchronous simulation
                    for (let step = 0; step < n; step++) {
                        let activeCount = 0;

                        for (const bot of game.bots) {
                            if (!bot.completed) {
                                bot.update();
                                activeCount++;
                            }
                        }

                        // Update completion count
                        game.completedCount = game.bots.filter(bot => bot.completed).length;

                        // If all bots completed, we can stop early
                        if (game.completedCount === 24 && step > 0) break;
                    }

                    // Force animation positions to match simulation positions
                    for (const bot of game.bots) {
                        bot.animX = bot.x;
                        bot.animY = bot.y;
                    }
                },
                reset() {
                    game.reset();
                }
            },
            writable: false,
            configurable: false
        });
    </script>
</body>
</html>
